/**
 * Vite plugin: substitute `__OK_CHROME_BG_LIGHT__` and `__OK_CHROME_BG_DARK__`
 * placeholders in `index.html` (and any `.html` Vite is transforming) with the
 * sRGB hex resolved from the `--sidebar` Tailwind v4 token.
 *
 * The plugin reads `packages/app/src/globals.css` at build start, resolves
 * OKLCH→sRGB via culori, then runs in `transformIndexHtml` with `enforce:
 * 'pre'` so the substitution applies before Vite's HTML rewriter touches the
 * inline `<style>`. The same resolved values are committed to
 * `packages/core/src/constants/chrome.ts` (regenerated by
 * `packages/core/scripts/generate-chrome-tokens.ts`); the drift test in
 * `packages/core/src/constants/chrome.test.ts` ensures the file stays in
 * sync with globals.css.
 *
 * Both pieces — `transformIndexHtml` inline-`<style>` substitution and
 * Tailwind v4 OKLCH→sRGB resolution via culori — were verified locally
 * against the existing `oklch(0.985 0 0)` / `oklch(0.205 0 0)` values;
 * both resolve to the existing literals (`#fafafa` / `#171717`). No
 * fallback path required; this Vite plugin is the canonical pipeline,
 * with `packages/core/scripts/generate-chrome-tokens.ts` as the
 * one-shot regenerator the drift test calls into.
 */
import { resolve } from 'node:path';
import type { Plugin } from 'vite';
import { resolveChromeTokensFromCss } from '../../../core/scripts/chrome-resolver.ts';

const LIGHT_PLACEHOLDER = '__OK_CHROME_BG_LIGHT__';
const DARK_PLACEHOLDER = '__OK_CHROME_BG_DARK__';

interface ChromeTokensPluginOptions {
  /** Absolute path to the globals.css file. Defaults to `<app>/src/globals.css`. */
  globalsCssPath?: string;
}

export function chromeTokensVitePlugin(options: ChromeTokensPluginOptions = {}): Plugin {
  const HERE = import.meta.dirname ?? new URL('.', import.meta.url).pathname;
  const cssPath = options.globalsCssPath ?? resolve(HERE, '../globals.css');
  let resolved: { light: string; dark: string } | null = null;

  function resolveOnce(): { light: string; dark: string } {
    if (resolved !== null) return resolved;
    resolved = resolveChromeTokensFromCss(cssPath);
    return resolved;
  }

  return {
    name: 'ok:chrome-tokens',
    enforce: 'pre',
    buildStart() {
      // Eager-resolve on every build so a failure surfaces in the build log
      // rather than later at the first index.html transform.
      resolveOnce();
    },
    transformIndexHtml: {
      order: 'pre',
      handler(html: string): string {
        const tokens = resolveOnce();
        return html
          .replaceAll(LIGHT_PLACEHOLDER, tokens.light)
          .replaceAll(DARK_PLACEHOLDER, tokens.dark);
      },
    },
  };
}
